# @zazcart/tools

A TypeScript utility library providing runtime type validation with full type inference, state management, and common helpers.

## Installation

```bash
bun add @zazcart/tools
```

## Quick Start

```typescript
import { createType, createModel, createMachine, createSlice, ms, invariant } from '@zazcart/tools';

// Define a validated type with full TypeScript inference
const UserSchema = createModel({
  id: 'number',
  name: 'string',
  email: 'string?',
  roles: 'string[]',
});

// Parse and validate data
const user = UserSchema.parse(data); // Throws if invalid
```

---

## Schema System

Runtime type validation with compile-time TypeScript inference.

### createType / createModel

```typescript
import { createType, createModel, InferType } from '@zazcart/tools';

// String-based definition
const StringType = createType('string');
const NumberArrayType = createType('number[]');
const OptionalStringType = createType('string?');

// Object schema with createModel (shorthand)
const UserSchema = createModel({
  id: 'number',
  name: 'string',
  email: 'string?',
});

// Equivalent using createType
const UserSchema2 = createType({
  properties: {
    id: 'number',
    name: 'string',
    email: 'string?',
  },
});

// Get TypeScript type from schema
type User = InferType<typeof UserSchema>;
// => { id: number; name: string; email?: string }
```

### Type Definitions

#### Primitive Types

| Definition | TypeScript Type | Description |
|------------|-----------------|-------------|
| `'string'` | `string` | String values |
| `'number'` | `number` | Numeric values (rejects NaN) |
| `'boolean'` | `boolean` | Boolean values |
| `'null'` | `null` | Null only |
| `'undefined'` | `undefined` | Undefined only |
| `'date'` | `Date` | Valid Date objects |
| `'function'` | `Function` | Any function |
| `'object'` | `object` | Plain objects |
| `'unknown'` | `unknown` | Any value (no validation) |
| `'any'` | `any` | Any value (no validation) |

#### Modifiers

| Modifier | Example | Result |
|----------|---------|--------|
| `?` (optional) | `'string?'` | `string \| undefined` |
| `[]` (array) | `'string[]'` | `string[]` |
| `[]?` (optional array) | `'string[]?'` | `string[] \| undefined` |

#### Object Definitions

```typescript
// Object with properties
createType({
  properties: {
    name: 'string',
    age: 'number',
    email: 'string?', // optional
  },
});

// Nested objects
createType({
  properties: {
    user: {
      properties: {
        name: 'string',
        address: {
          properties: {
            city: 'string',
            zip: 'string',
          },
        },
      },
    },
  },
});
```

#### Enum Definitions

```typescript
import { stringEnum } from '@zazcart/tools';

// Using stringEnum helper (recommended)
const StatusValues = stringEnum('pending', 'active', 'completed');
const StatusSchema = createType({ enum: StatusValues });

// Inline (requires 'as const')
const StatusSchema2 = createType({
  enum: ['pending', 'active', 'completed'] as const,
});

type Status = InferType<typeof StatusSchema>; // => 'pending' | 'active' | 'completed'
```

#### Union Definitions

```typescript
// Union of primitives
const StringOrNumber = createType({
  union: ['string', 'number'],
});

// Nullable type
const NullableString = createType({
  union: ['string', 'null'],
});

type Result = InferType<typeof StringOrNumber>; // => string | number
```

#### Array Definitions

```typescript
// Simple array (string shorthand)
const StringArray = createType('string[]');

// Array with items syntax
const StringArray2 = createType({ items: 'string' });

// Array of objects
const UserList = createType({
  items: {
    properties: {
      id: 'number',
      name: 'string',
    },
  },
});

// Using .list() method
const UserSchema = createModel({ id: 'number', name: 'string' });
const UserListSchema = UserSchema.list();
```

#### Record Definitions

```typescript
// Record<string, T>
const StringRecord = createType({ record: 'string' });
const NumberRecord = createType({ record: 'number' });

type Dict = InferType<typeof StringRecord>; // => Record<string, string>
```

### Schema Methods

```typescript
const Schema = createModel({
  id: 'number',
  name: 'string',
});

// .parse(value, path?) - Validate and return typed value, throws on error
const user = Schema.parse({ id: 1, name: 'John' });

// Parse from nested path
const user2 = Schema.parse(apiResponse, 'data.user');

// .parseList(value, path?) - Parse array of items
const users = Schema.parseList([{ id: 1, name: 'John' }]);

// .isValid(value) - Type guard, returns boolean
if (Schema.isValid(data)) {
  // data is typed as { id: number; name: string }
}

// .list() - Get array schema (cached)
const ListSchema = Schema.list();
```

### Helper Functions

```typescript
import { isType, invariantType } from '@zazcart/tools';

// isType - Type guard
const value: unknown = getData();
if (isType(value, 'string')) {
  // value is string
}
if (isType(value, 'date')) {
  // value is Date
}

// invariantType - Assert or throw
function processUser(data: unknown) {
  invariantType('object', data);
  // data is now typed as object
}

// Custom error message with placeholders
invariantType('string', value, processUser,
  'Expected $definition but got $typename: $originalMessage'
);
```

### Type Inference

```typescript
import { InferType, Type } from '@zazcart/tools';

const Schema = createModel({
  id: 'number',
  name: 'string',
  status: { enum: ['active', 'inactive'] as const },
  tags: 'string[]',
  metadata: 'object?',
});

// Extract TypeScript type
type MyType = InferType<typeof Schema>;
// => {
//   id: number;
//   name: string;
//   status: 'active' | 'inactive';
//   tags: string[];
//   metadata?: object;
// }

// Schema types are cached for string definitions
const a = createType('string');
const b = createType('string');
console.log(a === b); // true
```

---

## State Machine

Redux-like state management with slices, caching, and React hooks.

### createMachine

```typescript
import { createMachine, createSlice, createAsyncSlice } from '@zazcart/tools';

const machine = createMachine({
  id: 'app',
  slices: {
    counter: createSlice({
      id: 'counter',
      initial: { count: 0 },
      cache: 'session',
      reducers: {
        increment: (draft) => { draft.count += 1; },
        decrement: (draft) => { draft.count -= 1; },
        set: (draft, value: number) => { draft.count = value; },
      },
    }),
    user: createAsyncSlice({
      id: 'user',
      cache: 'user',
      context: { userID: '' },
      load: async (ctx) => {
        const res = await fetch(`/api/users/${ctx.userID}`);
        return res.json();
      },
    }),
  },
  selectors: {
    doubleCount: (state) => state.counter.count * 2,
  },
  context: { userID: 'user-123' },
});
```

### createSlice (Sync)

```typescript
const counterSlice = createSlice({
  id: 'counter',
  initial: { count: 0, history: [] as number[] },
  cache: 'session', // 'session' | 'user' | 'global'
  reducers: {
    // Reducers receive Immer draft - mutate directly
    increment: (draft) => {
      draft.count += 1;
    },
    add: (draft, amount: number) => {
      draft.count += amount;
      draft.history.push(draft.count);
    },
    reset: (draft) => {
      draft.count = 0;
      draft.history = [];
    },
  },
});
```

### createAsyncSlice

```typescript
const usersSlice = createAsyncSlice({
  id: 'users',
  cache: 'session',
  context: { page: 1 }, // Required context for load function
  initial: { value: [], loading: false }, // Optional initial override
  load: async (context) => {
    const response = await fetch(`/api/users?page=${context.page}`);
    return response.json();
  },
});

// Async slices automatically generate these actions:
// - load: Start loading (sets loading=true)
// - success: Set value on success
// - fail: Set error on failure
// - clear: Reset to initial state
```

### Async Slice State Shape

```typescript
type AsyncSliceState<T> = {
  loading: boolean;
  loaded: boolean;
  failed: boolean;
  error: string | null;
  value: T | null;
  changes: number;
};
```

### Cache Strategies

| Strategy | Description |
|----------|-------------|
| `'session'` | Invalidate when sessionID changes |
| `'user'` | Invalidate when userID changes |
| `'global'` | Never automatically invalidate |

### Machine API

```typescript
const machine = createMachine({ id: 'app', slices: { ... } });

// Dispatch actions
machine.dispatch(machine.actions.counter.increment());
machine.dispatch(machine.actions.counter.add(5));

// Get current state
const state = machine.getState();

// Subscribe to changes
const unsubscribe = machine.subscribe((state, prevState) => {
  console.log('State changed:', state);
});

// Reset to initial state
machine.reset();

// Access action creators and types
machine.actions.counter.increment(); // => { type: '@app/counter/increment', payload: undefined }
machine.actionTypes.counter.increment; // => '@app/counter/increment'

// Context management
machine.getContext(); // => { userID: 'user-123' }
machine.provideContext({ userID: 'new-user' });

// Direct reducer access (for Redux integration)
const rootReducer = machine.reducer;
```

### React Hooks

```typescript
// In a React component
function Counter() {
  // useMachine - Get actions and full state
  const { state, actions, dispatch } = machine.useMachine();

  // useSelector - Select specific state slice
  const count = machine.useSelector((s) => s.counter.count);
  const doubled = machine.useSelector((s) => s.doubleCount); // From selectors

  return (
    <div>
      <p>Count: {count}</p>
      <button onClick={() => dispatch(actions.counter.increment())}>+</button>
    </div>
  );
}

// Named exports for specific machine
const { useApp, useAppSelector } = machine;
// useApp() and useAppSelector() are aliases for useMachine/useSelector
```

---

## Helpers

### Error Utilities

```typescript
import {
  InvariantError,
  invariant,
  tryCatch,
  moveStackTrace,
  createErrorList
} from '@zazcart/tools';

// invariant - Assert truthy or throw
invariant(user, 'User is required');
invariant(user.id, (typeName) => `Expected id, got ${typeName}`);

// tryCatch - Safe execution returning tuple
const [error, result] = tryCatch(() => JSON.parse(data));
if (error) {
  console.error('Parse failed:', error.message);
} else {
  console.log('Parsed:', result);
}

// InvariantError - Custom error with clean stack traces
throw new InvariantError('Invalid input', myFunction, { debug: data });

// moveStackTrace - Clean error origins
function validate(data: unknown) {
  return moveStackTrace(() => {
    if (!data) throw new Error('Data required');
    return data;
  }, validate); // Error points to validate() caller
}

// createErrorList - Collect multiple errors
const errors = createErrorList('Validation failed: ');
if (!name) errors.add('name is required');
if (!email) errors.add('email is required');
errors.check(); // Throws if any errors added
```

### Object Utilities

```typescript
import {
  getProperty,
  setProperty,
  objectKeys,
  objectEntries,
  objectValues,
  isObject,
  assertObject,
  keyBy,
  reduceObject,
  requireAll,
  deepFreeze,
} from '@zazcart/tools';

// getProperty - Type-safe deep access
const user = { profile: { name: 'John', age: 30 } };
const name = getProperty(user, 'profile.name'); // 'John' (throws if falsy)
const age = getProperty(user, 'profile.age', true); // 30 (allows falsy)

// setProperty - Type-safe deep set
setProperty(user, 'profile.name', 'Jane');

// Typed object iteration
const obj = { a: 1, b: 2 };
objectKeys(obj);    // ('a' | 'b')[]
objectEntries(obj); // ['a', 1] | ['b', 2][]
objectValues(obj);  // number[]

// isObject / assertObject
if (isObject(data)) { /* data is Record<string, unknown> */ }
assertObject(data); // throws if not plain object

// keyBy - Create lookup from array
const users = [{ id: 1, name: 'A' }, { id: 2, name: 'B' }];
const byId = keyBy(users, 'id'); // { 1: {...}, 2: {...} }
const byName = keyBy(users, (u) => u.name); // { A: {...}, B: {...} }

// reduceObject - Reduce over entries
const doubled = reduceObject({ a: 1, b: 2 }, ([k, v]) => ({ [k]: v * 2 }));
// => { a: 2, b: 4 }

// requireAll - Assert all properties are truthy
const config = requireAll({ host, port, db }); // throws if any falsy

// deepFreeze - Recursively freeze object
const frozen = deepFreeze({ nested: { value: 1 } });
```

### Type Utilities

```typescript
import { stringEnum } from '@zazcart/tools';
import type {
  AnyRecord,
  UnknownRecord,
  Simplify,
  Merge,
  Paths,
  PathType,
  PromiseValue,
  MaybePromise,
  MaybeArray,
  Writable,
  PartialFields,
  UnionToIntersection,
  Primitive,
  Serializable,
  AnyFunction,
  IsAny,
  IsNever,
  IsOptional,
  Cast,
  Join,
} from '@zazcart/tools';

// stringEnum - Create typed string array for enums
const Status = stringEnum('pending', 'active', 'done');
type StatusType = (typeof Status)[number]; // 'pending' | 'active' | 'done'

// Simplify - Flatten intersection types for readability
type Flat = Simplify<{ a: 1 } & { b: 2 }>; // { a: 1; b: 2 }

// Merge - Deep merge two types
type Merged = Merge<{ a: 1; b: 2 }, { b: 3; c: 4 }>; // { a: 1; b: 3; c: 4 }

// Paths - Get all valid paths of an object
type UserPaths = Paths<{ user: { name: string } }>; // 'user' | 'user.name'

// PathType - Get type at path
type NameType = PathType<{ user: { name: string } }, 'user.name'>; // string

// PromiseValue - Extract resolved type
type Value = PromiseValue<Promise<string>>; // string

// MaybePromise - T | Promise<T>
type MaybeString = MaybePromise<string>; // string | Promise<string>

// MaybeArray - T | T[]
type MaybeStrings = MaybeArray<string>; // string | string[]

// Writable - Remove readonly modifiers
type Mutable = Writable<{ readonly a: 1 }>; // { a: 1 }

// PartialFields - Make specific fields optional
type Partial = PartialFields<{ a: 1; b: 2; c: 3 }, ['a', 'b']>;
// { a?: 1; b?: 2; c: 3 }

// UnionToIntersection
type Inter = UnionToIntersection<{ a: 1 } | { b: 2 }>; // { a: 1 } & { b: 2 }

// Primitive types
type P = Primitive; // string | number | boolean | null | undefined | bigint | symbol

// Join - Join array as string type
type Joined = Join<['a', 'b', 'c'], '.'>; // 'a.b.c'
```

### Time Utilities

```typescript
import { ms } from '@zazcart/tools';

// Convert time strings to milliseconds
ms('1s');   // 1000
ms('5m');   // 300000
ms('2h');   // 7200000
ms('1d');   // 86400000
ms('1w');   // 604800000
ms('1mo');  // ~2629746000 (1 month)
ms('1y');   // ~31556952000 (1 year)

// Also accepts numbers (treated as ms)
ms(1000);   // 1000

// Type-safe time strings
import type { MSTimeString } from '@zazcart/tools';
const timeout: MSTimeString = '30s';
```

### Other Utilities

```typescript
import {
  getTypeOf,
  maskData,
  delay,
  createProxy,
  formatDate,
  setDefaultDateLocale,
  getDefaultDateLocale,
  EMPTY
} from '@zazcart/tools';

// getTypeOf - Get readable type name
getTypeOf(null);          // 'Null'
getTypeOf(NaN);           // 'NaN'
getTypeOf(new Date());    // 'Date'
getTypeOf([]);            // 'Array'
getTypeOf({});            // 'Object'

// maskData - Mask values for safe logging
maskData({ password: 'secret', user: { email: 'a@b.com' } });
// => { password: 'String', user: { email: 'String' } }

// delay - Promise-based setTimeout
await delay(1000); // Wait 1 second
await delay();     // Default 500ms

// createProxy - Lazy initialization
const heavyObject = createProxy(() => {
  console.log('Initialized!');
  return computeExpensiveValue();
});
// 'Initialized!' only logs on first access

// formatDate - Format dates with optional locale
formatDate(new Date(), 'yyyy-MM-dd'); // '2025-12-15'
formatDate('2025-09-25', 'MMM dd'); // 'Sep 25'

// Set global default locale
import { ptBR } from 'date-fns/locale';
setDefaultDateLocale(ptBR);
formatDate(new Date(), 'MMMM'); // 'dezembro'

// Override locale for single call
import { enUS } from 'date-fns/locale';
formatDate(new Date(), 'MMMM', { locale: enUS }); // 'December'

// Get current default locale
getDefaultDateLocale(); // Locale | null

// EMPTY - Unique symbol for empty/unset values
const cache = new Map<string, typeof EMPTY | Data>();
cache.set('key', EMPTY); // Distinguish from undefined
```

---

