import { isObject } from '../helpers/object-utils';
import { UnknownRecord } from '../helpers/type-utils';
import { invariantType } from '../schema';

import {
  MachineAction,
  MachineReducer,
  UnknownAction,
  WithMetadata,
} from './models';

export namespace Store {
  export type Unsubscribe = () => void;

  export type ActionListener = (action: UnknownAction) => void;

  export type Listener<State> = (state: State, action: MachineAction) => void;

  export type Subscription<State = any> = (
    listener: Listener<State>,
  ) => Unsubscribe;

  export type Instance<State = UnknownRecord> = {
    getState(): WithMetadata<State>;
    dispatch(action: any): any;
    subscribe: Subscription<State>;
  };

  export type SetupParams<State> = {
    reducer: MachineReducer<State>;
    getInitialState(): State;
    machineID: string;
  };

  export function create<State>(params: SetupParams<State>): Instance<State> {
    const { getInitialState, reducer, machineID } = params;

    let currentReducer = reducer;
    let currentState = getInitialState();
    let currentListeners: Listener<State>[] = [];

    function getState() {
      return currentState;
    }

    function subscribe(listener: Listener<State>) {
      invariantType('function', listener, subscribe);
      currentListeners.push(listener);

      return function unsubscribe() {
        const index = currentListeners.indexOf(listener);
        currentListeners.splice(index, 1);
      };
    }

    function dispatch(action: MachineAction): UnknownAction {
      if (!isObject(action)) {
        throw new Error('Actions must be plain objects.');
      }
      if (typeof action.type === 'undefined') {
        throw new Error('Actions may not have an undefined "type" property.');
      }

      currentState = currentReducer(currentState, action);

      for (const listener of currentListeners) {
        listener(currentState, action);
      }

      return action;
    }

    dispatch({ type: `@@${machineID}/init` });

    return {
      dispatch,
      subscribe,
      getState,
    } as Instance<any>;
  }
}

