  );

  const actions = isSliceKey
    ? runtimeActions[path as StringTypes.SliceKey]
    : undefined;

  const selection = useSelector(state => getProperty(state, path, true));

  // Return clean object shape for V8 optimization
  return {
    state: selection,
    actions,
    dispatch: store.dispatch,
  };
}

